  return (
    <div className="flex flex-col gap-6 p-6 bg-slate-900 border-r border-slate-800 h-full overflow-y-auto custom-scrollbar">
      <div className="flex items-center gap-2 mb-2">
        <div className="w-2 h-8 bg-teal-500 rounded-full"></div>
        <h2 className="text-xl font-bold text-white tracking-tight">Otimizador de Conteúdo SEO</h2>
      </div>

      <div className="space-y-4">
        <div>
          <label className="block text-sm font-medium text-slate-400 mb-1.5 uppercase tracking-wider">
            Código HTML Original
          </label>
          <textarea
            value={html}
            onChange={(e) => setHtml(e.target.value)}
            className="w-full h-64 bg-slate-800 border border-slate-700 rounded-lg p-3 text-slate-200 font-mono text-sm focus:ring-2 focus:ring-teal-500 focus:border-transparent outline-none transition-all placeholder-slate-600"
            placeholder="Cole seu HTML aqui..."
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-slate-400 mb-1.5 uppercase tracking-wider">
            Requisitos de Modificação
          </label>
          <textarea
            value={reqs}
            onChange={(e) => setReqs(e.target.value)}
            className="w-full h-24 bg-slate-800 border border-slate-700 rounded-lg p-3 text-slate-200 text-sm focus:ring-2 focus:ring-teal-500 focus:border-transparent outline-none transition-all placeholder-slate-600"
            placeholder="Ex: Mudar contexto de vídeo para imagem, focar em Gemini prompts..."
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-slate-400 mb-1.5 uppercase tracking-wider">
            Keywords Alvo
          </label>
          <input
            type="text"
            value={keywords}
            onChange={(e) => setKeywords(e.target.value)}
            className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-slate-200 text-sm focus:ring-2 focus:ring-teal-500 focus:border-transparent outline-none transition-all placeholder-slate-600"
            placeholder="Ex: gerador de imagem ai, criar arte digital gratis"
          />
        </div>
      </div>

      <button
        onClick={onOptimize}
        disabled={isOptimizing || !html || !reqs || !keywords}
        className={`mt-4 py-4 px-6 rounded-xl font-bold text-lg flex items-center justify-center gap-2 transition-all duration-300 ${
          isOptimizing 
          ? "bg-slate-700 cursor-not-allowed text-slate-500" 
          : "bg-gradient-to-r from-teal-500 to-emerald-600 hover:from-teal-400 hover:to-emerald-500 text-white shadow-lg shadow-teal-500/20 active:scale-95"
        }`}
      >
        {isOptimizing ? (
          <>
            <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
              <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
              <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
            </svg>
            Otimizando...
          </>
        ) : (
          "Otimizar Agora"
        )}
      </button>
    </div>
  );
};

import React, { useState } from 'react';
import { SEOOutput } from '../types';

interface ResultsSectionProps {
  result: SEOOutput | null;
}

export const ResultsSection: React.FC<ResultsSectionProps> = ({ result }) => {
  const [activeTab, setActiveTab] = useState<'code' | 'preview'>('code');

  if (!result) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-slate-500 p-12 bg-slate-950">
        <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 mb-4 opacity-20" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M19 20H5a2 2 0 01-2-2V6a2 2 0 012-2h10l4 4v10a2 2 0 01-2 2z" />
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M14 2v6h6M8 12h8m-8 4h5" />
        </svg>
        <p className="text-xl font-medium">Pronto para otimizar</p>
        <p className="text-sm mt-2 max-w-xs text-center">Insira os dados à esquerda e clique em "Otimizar Agora" para gerar os ativos SEO.</p>
      </div>
    );
  }

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    alert("Copiado com sucesso!");
  };

  return (
    <div className="flex flex-col h-full bg-slate-950 overflow-hidden">
      <div className="p-6 border-b border-slate-800 bg-slate-900/50 backdrop-blur-md">
        <h3 className="text-sm font-bold text-teal-400 uppercase tracking-widest mb-4">Ativos Gerados</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="bg-slate-800 p-4 rounded-xl border border-slate-700">
            <div className="flex justify-between items-center mb-2">
              <span className="text-xs font-semibold text-slate-400">Sugestão de URL</span>
              <button onClick={() => copyToClipboard(result.url)} className="text-teal-500 hover:text-teal-400 text-xs font-bold">COPIAR</button>
            </div>
            <p className="text-sm text-white font-mono break-all">{result.url}</p>
          </div>
          <div className="bg-slate-800 p-4 rounded-xl border border-slate-700">
            <div className="flex justify-between items-center mb-2">
              <span className="text-xs font-semibold text-slate-400">Browser Title</span>
              <button onClick={() => copyToClipboard(result.browserTitle)} className="text-teal-500 hover:text-teal-400 text-xs font-bold">COPIAR</button>
            </div>
            <p className="text-sm text-white font-medium">{result.browserTitle}</p>
          </div>
          <div className="bg-slate-800 p-4 rounded-xl border border-slate-700 md:col-span-2">
            <div className="flex justify-between items-center mb-2">
              <span className="text-xs font-semibold text-slate-400">Meta Description</span>
              <button onClick={() => copyToClipboard(result.metaDescription)} className="text-teal-500 hover:text-teal-400 text-xs font-bold">COPIAR</button>
            </div>
            <p className="text-sm text-slate-300 italic">"{result.metaDescription}"</p>
          </div>
        </div>
      </div>

      <div className="flex-1 overflow-hidden flex flex-col">
        <div className="flex items-center gap-4 px-6 pt-4">
          <button 
            onClick={() => setActiveTab('code')}
            className={`pb-3 text-sm font-bold tracking-wide transition-all border-b-2 ${activeTab === 'code' ? 'border-teal-500 text-teal-500' : 'border-transparent text-slate-500 hover:text-slate-300'}`}
          >
            CÓDIGO MODIFICADO
          </button>
          <button 
            onClick={() => setActiveTab('preview')}
            className={`pb-3 text-sm font-bold tracking-wide transition-all border-b-2 ${activeTab === 'preview' ? 'border-teal-500 text-teal-500' : 'border-transparent text-slate-500 hover:text-slate-300'}`}
          >
            PRÉ-VISUALIZAÇÃO
          </button>
        </div>

        <div className="flex-1 overflow-auto custom-scrollbar p-6">
          {activeTab === 'code' ? (
            <div className="relative">
              <button 
                onClick={() => copyToClipboard(result.modifiedHtml)}
                className="absolute top-2 right-2 bg-slate-700 hover:bg-slate-600 text-white px-3 py-1 rounded text-xs font-bold transition-colors z-10"
              >
                COPIAR TUDO
              </button>
              <pre className="bg-slate-900 p-6 rounded-xl border border-slate-800 text-xs font-mono text-emerald-400 overflow-x-auto whitespace-pre-wrap leading-relaxed shadow-inner">
                {result.modifiedHtml}
              </pre>
            </div>
          ) : (
            <div className="bg-white rounded-xl h-full shadow-2xl overflow-hidden border border-slate-700">
               <iframe 
                srcDoc={result.modifiedHtml} 
                className="w-full h-full border-none"
                title="Preview"
              />
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { InputSection } from './components/InputSection';
import { ResultsSection } from './components/ResultsSection';
import { optimizeContent } from './services/geminiService';
import { SEOOutput } from './types';

const App: React.FC = () => {
  const [html, setHtml] = useState('');
  const [reqs, setReqs] = useState('');
  const [keywords, setKeywords] = useState('');
  const [result, setResult] = useState<SEOOutput | null>(null);
  const [isOptimizing, setIsOptimizing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleOptimize = async () => {
    setIsOptimizing(true);
    setError(null);
    try {
      const data = await optimizeContent({
        originalHtml: html,
        requirements: reqs,
        keywords: keywords
      });
      setResult(data);
    } catch (err) {
      console.error(err);
      setError("Falha ao otimizar o conteúdo. Verifique sua chave de API e tente novamente.");
    } finally {
      setIsOptimizing(false);
    }
  };

  return (
    <div className="flex flex-col lg:flex-row h-screen bg-slate-950 overflow-hidden">
      {/* Sidebar - Inputs */}
      <div className="w-full lg:w-[400px] xl:w-[500px] flex-shrink-0 h-1/2 lg:h-full">
        <InputSection 
          html={html}
          setHtml={setHtml}
          reqs={reqs}
          setReqs={setReqs}
          keywords={keywords}
          setKeywords={setKeywords}
          isOptimizing={isOptimizing}
          onOptimize={handleOptimize}
        />
      </div>

      {/* Main Panel - Results */}
      <div className="flex-1 h-1/2 lg:h-full relative">
        {error && (
          <div className="absolute top-4 left-1/2 -translate-x-1/2 z-50 bg-rose-500/20 border border-rose-500/50 text-rose-200 px-6 py-3 rounded-lg backdrop-blur-md shadow-2xl flex items-center gap-3">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
              <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
            </svg>
            <span className="text-sm font-medium">{error}</span>
          </div>
        )}
        <ResultsSection result={result} />
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);
